import Link from "next/link";
import { getAdminClientOrNull } from "@/lib/supabase/admin";
import { AdminConfigMissing } from "@/components/AdminConfigMissing";
import { getCurrentDbUser } from "@/lib/auth/get-current-user";
import { redirect } from "next/navigation";
import { AdicionarDimensionForm } from "./AdicionarDimensionForm";
import { DeleteDimensionButton } from "./DeleteDimensionButton";

export const dynamic = "force-dynamic";

export default async function AdminComponentesGeraisPage() {
  const dbUser = await getCurrentDbUser();
  if (!dbUser || dbUser.role !== "ADMIN") redirect("/dashboard");

  const result = getAdminClientOrNull();
  if (!result.client) return <AdminConfigMissing errorType={result.error} />;
  const supabase = result.client;

  const { data: dimensions } = await supabase
    .from("GeneralDimension")
    .select("id, code, name, sortOrder")
    .order("sortOrder", { ascending: true });

  const list = dimensions ?? [];

  return (
    <div style={{ maxWidth: "min(560px, 100%)" }}>
      <div
        style={{
          display: "flex",
          flexWrap: "wrap",
          alignItems: "center",
          gap: "clamp(12px, 3vw, 16px)",
          marginBottom: "clamp(20px, 5vw, 24px)",
        }}
      >
        <Link
          href="/admin"
          style={{
            color: "var(--text-secondary)",
            fontSize: "clamp(15px, 3.8vw, 17px)",
            textDecoration: "none",
            fontWeight: 500,
          }}
        >
          ÔåÉ Voltar
        </Link>
        <h1 style={{ margin: 0, fontSize: "clamp(20px, 5vw, 24px)", fontWeight: 600, color: "var(--text-primary)" }}>
          Componentes gerais
        </h1>
      </div>

      <p style={{ margin: "0 0 clamp(16px, 4vw, 20px) 0", fontSize: "clamp(14px, 3.5vw, 16px)", color: "var(--text-secondary)" }}>
        Estas componentes s├úo padr├úo em todas as modalidades (T├®cnico, T├ítico, F├¡sico, Mental, Te├│rico). Podes adicionar novas. Em cada modalidade, os crit├®rios dentro de cada componente s├úo configur├íveis em <Link href="/admin/avaliacao" style={{ color: "var(--primary)", textDecoration: "underline" }}>Crit├®rios de avalia├º├úo</Link>.
      </p>

      <ul style={{ listStyle: "none", padding: 0, margin: 0, display: "flex", flexDirection: "column", gap: "clamp(10px, 2.5vw, 12px)" }}>
        {list.map((d) => (
          <li
            key={d.id}
            className="card"
            style={{ padding: "clamp(14px, 3.5vw, 18px)", display: "flex", flexWrap: "wrap", alignItems: "center", justifyContent: "space-between", gap: 12 }}
          >
            <div style={{ display: "flex", flexWrap: "wrap", alignItems: "center", gap: 8 }}>
              <span style={{ fontSize: "clamp(15px, 3.8vw, 17px)", fontWeight: 600, color: "var(--text-primary)" }}>
                {d.name}
              </span>
              <span
                style={{
                  fontSize: "clamp(12px, 3vw, 14px)",
                  padding: "2px 8px",
                  borderRadius: "var(--radius-md)",
                  backgroundColor: "var(--bg)",
                  color: "var(--text-secondary)",
                  fontFamily: "monospace",
                }}
              >
                {d.code}
              </span>
            </div>
            <DeleteDimensionButton dimensionId={d.id} dimensionName={d.name} />
          </li>
        ))}
      </ul>

      <AdicionarDimensionForm />
    </div>
  );
}

"use client";

import { useState } from "react";
import { useFormState } from "react-dom";
import { getTranslations } from "@/lib/i18n";
import type { Locale } from "@/lib/i18n";
import { updateAttendanceGoal, type UpdateAttendanceGoalResult } from "./actions";
import { SuccessConfirmModal } from "@/components/SuccessConfirmModal";

type Props = { initialTargetValue: number; initialLocale: Locale };

export function MetaAssiduidadeForm({ initialTargetValue, initialLocale }: Props) {
  const t = getTranslations(initialLocale);
  const [userDismissed, setUserDismissed] = useState(false);
  const wrappedAction = async (prev: UpdateAttendanceGoalResult | null, formData: FormData) => {
    setUserDismissed(false);
    return updateAttendanceGoal(prev, formData);
  };
  const [state, formAction] = useFormState(wrappedAction, null as UpdateAttendanceGoalResult | null);

  const showSuccess = Boolean(state?.success && !state?.error && !userDismissed);

  return (
    <>
      <SuccessConfirmModal
        open={showSuccess}
        onClose={() => setUserDismissed(true)}
        title={t("savedSuccessTitle")}
        message={t("savedSuccessMessage")}
        closeLabel={t("closeConfirm")}
      />
      <form action={formAction} style={{ display: "flex", flexDirection: "column", gap: "clamp(12px, 3vw, 16px)" }}>
        <label style={{ display: "flex", flexDirection: "column", gap: 6 }}>
          <span style={{ fontSize: "clamp(14px, 3.5vw, 16px)", fontWeight: 500, color: "var(--text-primary)" }}>
            {t("classesPerMonth")}
          </span>
          <input
            type="number"
            name="target_value"
            defaultValue={initialTargetValue}
            className="input"
            min={1}
            max={99}
            required
            style={{ maxWidth: 120 }}
          />
        </label>
        {state?.error && (
          <p style={{ margin: 0, fontSize: "clamp(14px, 3.5vw, 16px)", color: "var(--danger)" }}>{state.error}</p>
        )}
        <button type="submit" className="btn btn-primary" style={{ minHeight: 44, alignSelf: "flex-start" }}>
          {t("saveGoal")}
        </button>
      </form>
    </>
  );
}

"use server";

import { revalidatePath } from "next/cache";
import { getCurrentDbUser } from "@/lib/auth/get-current-user";
import { createAdminClient } from "@/lib/supabase/admin";

export type UpdateAttendanceGoalResult = { error?: string; success?: boolean };

export async function updateAttendanceGoal(
  _prev: UpdateAttendanceGoalResult | null,
  formData: FormData
): Promise<UpdateAttendanceGoalResult> {
  const dbUser = await getCurrentDbUser();
  if (!dbUser || dbUser.role !== "ADMIN") return { error: "N├úo autorizado." };

  const valueStr = (formData.get("target_value") as string)?.trim();
  const value = valueStr ? parseInt(valueStr, 10) : 10;
  if (isNaN(value) || value < 1 || value > 99) return { error: "Meta deve ser entre 1 e 99 aulas." };

  const supabase = createAdminClient();
  const { data: existing } = await supabase
    .from("AttendanceGoal")
    .select("id")
    .eq("is_global", true)
    .limit(1)
    .single();

  if (existing) {
    const { error } = await supabase
      .from("AttendanceGoal")
      .update({ target_value: value })
      .eq("id", existing.id);
    if (error) return { error: error.message };
  } else {
    const { error } = await supabase.from("AttendanceGoal").insert({
      target_value: value,
      period_type: "MONTHLY",
      is_global: true,
    });
    if (error) return { error: error.message };
  }

  revalidatePath("/admin/configuracoes");
  revalidatePath("/dashboard");
  return { success: true };
}

import Link from "next/link";
import { getAdminClientOrNull } from "@/lib/supabase/admin";
import { AdminConfigMissing } from "@/components/AdminConfigMissing";
import { getCurrentDbUser } from "@/lib/auth/get-current-user";
import { redirect } from "next/navigation";
import { getLocaleFromCookies } from "@/lib/theme-locale-server";
import { getTranslations } from "@/lib/i18n";
import { MetaAssiduidadeForm } from "./MetaAssiduidadeForm";

export default async function AdminConfiguracoesPage() {
  const dbUser = await getCurrentDbUser();
  if (!dbUser || dbUser.role !== "ADMIN") redirect("/dashboard");

  const locale = await getLocaleFromCookies();
  const t = getTranslations(locale as "pt" | "en");
  const result = getAdminClientOrNull();
  if (!result.client) return <AdminConfigMissing errorType={result.error} />;
  const supabase = result.client;
  const { data: goal } = await supabase
    .from("AttendanceGoal")
    .select("id, target_value")
    .eq("is_global", true)
    .limit(1)
    .single();

  return (
    <div style={{ maxWidth: "min(480px, 100%)" }}>
      <div style={{ marginBottom: "clamp(20px, 5vw, 24px)" }}>
        <Link
          href="/admin"
          style={{
            color: "var(--text-secondary)",
            fontSize: "clamp(15px, 3.8vw, 17px)",
            textDecoration: "none",
            fontWeight: 500,
          }}
        >
          ÔåÉ {t("back")}
        </Link>
      </div>
      <h1 style={{ margin: "0 0 8px 0", fontSize: "clamp(20px, 5vw, 24px)", fontWeight: 600, color: "var(--text-primary)" }}>
        {t("navSettings")}
      </h1>
      <p style={{ margin: "0 0 clamp(24px, 6vw, 32px) 0", fontSize: "clamp(14px, 3.5vw, 16px)", color: "var(--text-secondary)" }}>
        {t("settingsDescription")}
      </p>

      <section className="card" style={{ padding: "clamp(20px, 5vw, 24px)" }}>
        <h2 style={{ margin: "0 0 clamp(12px, 3vw, 16px) 0", fontSize: "clamp(16px, 4vw, 18px)", fontWeight: 600, color: "var(--text-primary)" }}>
          {t("attendanceGoalGlobal")}
        </h2>
        <p style={{ margin: "0 0 clamp(16px, 4vw, 20px) 0", fontSize: "clamp(14px, 3.5vw, 16px)", color: "var(--text-secondary)" }}>
          {t("attendanceGoalHint")}
        </p>
        <MetaAssiduidadeForm initialTargetValue={goal?.target_value ?? 10} initialLocale={locale as "pt" | "en"} />
      </section>
    </div>
  );
}
